const SPEED = 200;
const GRAVITY = 500;
const JUMP_POWER = 300;
const GROUND_Y = 250; // Approximate ground level

if (!state.playerVelocityY) state.playerVelocityY = 0;
if (!state.isJumping) state.isJumping = false;
if (!state.coins) state.coins = 0;
if (!state.lives) state.lives = 3;

// Horizontal movement
let moveX = 0;
if (Input.isKeyPressed('a') || Input.isKeyPressed('A')) moveX = -SPEED;
if (Input.isKeyPressed('d') || Input.isKeyPressed('D')) moveX = SPEED;
self.x += moveX * dt;

// Apply gravity
state.playerVelocityY += GRAVITY * dt;
self.y += state.playerVelocityY * dt;

// Platform collision detection
let platforms = [
  { x: 0, y: 280, w: 800, h: 40 },     // Main ground
  { x: -150, y: 180, w: 200, h: 20 },  // Platform 1
  { x: 150, y: 180, w: 200, h: 20 },   // Platform 2
  { x: 0, y: 80, w: 200, h: 20 }       // Platform 3
];

let isOnGround = false;
for (let p of platforms) {
  // Check if player is above platform and falling
  if (state.playerVelocityY >= 0 &&
      self.y + 15 >= p.y - 5 && // Player bottom touching platform top
      self.y + 15 <= p.y + p.h + 5 &&
      self.x + 10 > p.x - p.w/2 &&
      self.x - 10 < p.x + p.w/2) {
    self.y = p.y - 15;
    state.playerVelocityY = 0;
    state.isJumping = false;
    isOnGround = true;
  }
}

// Jump
if ((Input.isKeyPressed(' ') || Input.isKeyPressed('Space')) && !state.isJumping && isOnGround) {
  state.playerVelocityY = -JUMP_POWER;
  state.isJumping = true;
}

// Goomba collision detection (game over)
let goombaList = ['Goomba_1', 'Goomba_2', 'Goomba_3'];
for (let gName of goombaList) {
  let goomba = entities.get(gName);
  if (goomba) {
    let dx = self.x - goomba.x;
    let dy = self.y - goomba.y;
    let dist = Math.sqrt(dx*dx + dy*dy);
    if (dist < 25) {
      state.lives -= 1;
      if (state.lives > 0) {
        // Reset player position
        self.x = 0;
        self.y = 150;
        state.playerVelocityY = 0;
      }
    }
  }
}

// Coin collection
let coinList = ['Coin_1', 'Coin_2', 'Coin_3', 'Coin_4', 'Coin_5'];
for (let cName of coinList) {
  let coin = entities.get(cName);
  if (coin && coin.visible) {
    let dx = self.x - coin.x;
    let dy = self.y - coin.y;
    let dist = Math.sqrt(dx*dx + dy*dy);
    if (dist < 20) {
      state.coins += 1;
      coin.visible = false;
    }
  }
}

// Screen bounds
if (self.x > 420) self.x = -420;
if (self.x < -420) self.x = 420;

template.script:
const SPEED = 80;

if (!state.goombaDir) state.goombaDir = {};
let id = self.name || 'unknown';
if (!state.goombaDir[id]) state.goombaDir[id] = -1;

// Patrol movement
self.x += SPEED * state.goombaDir[id] * dt;

// Bounce at edges
if (self.x < -400) state.goombaDir[id] = 1;
if (self.x > 400) state.goombaDir[id] = -1;

