// Update UI text with current game state
let uiText = `Coins: ${state.coins || 0} | Lives: ${state.lives || 3}`;

// Reference to update the UI display
let uiDisplay = entities.get('UI Display');
if (uiDisplay) {
  // Store the content to be displayed
  state.uiContent = uiText;
}

